import React, { useMemo } from 'react';
import { Typography } from '@material-ui/core';
import { makeStyles } from '@material-ui/core/styles';
import { getFormattedDateForLanguage } from '../utils/gatsby-frontend-helpers';

// Components
import Link from './Link';

const useStyles = makeStyles((theme) => ({
    blogPostWrapper: {
        padding: '5px 0',
    },
}));

const SimplePostsList = ({
    className,
    posts,
    quantity,
    locale,
}) => {
    const classes = useStyles();

    let postsLoop = useMemo(() => posts.filter(
        ({ node }) => new Date().toISOString() >= node.frontmatter.date
    ), [posts]);

    if (quantity) {
        postsLoop = postsLoop.slice(0, quantity);
    }

    return (
        <div className={className}>
            {postsLoop.map(({ node }) => {
                const title = node.frontmatter.title || node.fields.slug;
                return (
                    <article
                        key={node.fields.slug}
                        className={classes.blogPostWrapper}
                    >
                        <header>
                            <Typography
                                color="textPrimary"
                                variant="h6"
                            >
                                <Link
                                    className={classes.blogPostLink}
                                    color="textPrimary"
                                    to={node.fields.path}
                                >
                                    {title}
                                </Link>
                            </Typography>
                            <Typography
                                className={classes.blogPostDate}
                                color="textSecondary"
                                variant="body2"
                            >
                                {getFormattedDateForLanguage(node.frontmatter.date, locale)}
                            </Typography>
                        </header>
                    </article>
                );
            })}
        </div>
    );
};

export default SimplePostsList;
